  1	import * as React from 'react';
  2	import { createWizardNodeState } from '@odf/core/components/utils';
  3	import { useNodesData } from '@odf/core/hooks';
  4	import { NodeData } from '@odf/core/types';
  5	import { useCustomTranslation } from '@odf/shared';
  6	import {
  7	  Card,
  8	  CardHeader,
  9	  Flex,
 10	  CardTitle,
 11	  CardBody,
 12	  FlexItem,
 13	  Alert,
 14	} from '@patternfly/react-core';
 15	import { WizardNodeState } from '../../reducer';
 16	import { SelectNodesTable } from '../../select-nodes-table/select-nodes-table';
 17	import './NodesSection.scss';
 18	
 19	type NodesSectionProps = {
 20	  isDisabled?: boolean;
 21	  selectedNodes: WizardNodeState[];
 22	  setSelectedNodes: (nodes: WizardNodeState[]) => void;
 23	  allNodesDescription?: string;
 24	  selectNodesDescription?: string;
 25	};
 26	
 27	export const NodesSection: React.FC<NodesSectionProps> = React.memo(
 28	  ({
 29	    isDisabled,
 30	    selectedNodes,
 31	    setSelectedNodes,
 32	    allNodesDescription,
 33	    selectNodesDescription,
 34	  }) => {
 35	    const { t } = useCustomTranslation();
 36	    const [isUseAllNodes, setIsUseAllNodes] = React.useState(true);
 37	    const [allNodes, allNodesLoaded] = useNodesData(true);
 38	
 39	    const onNodeSelect = React.useCallback(
 40	      (nodes: NodeData[]) => {
 41	        const nodesData = createWizardNodeState(nodes);
 42	        setSelectedNodes(nodesData);
 43	      },
 44	      [setSelectedNodes]
 45	    );
 46	
 47	    // Initialize selected nodes when component mounts and "All nodes" is selected by default
 48	    React.useEffect(() => {
 49	      if (
 50	        isUseAllNodes &&
 51	        allNodesLoaded &&
 52	        allNodes.length > 0 &&
 53	        selectedNodes.length === 0
 54	      ) {
 55	        onNodeSelect(allNodes);
 56	      }
 57	    }, [
 58	      isUseAllNodes,
 59	      allNodesLoaded,
 60	      allNodes,
 61	      selectedNodes.length,
 62	      onNodeSelect,
 63	    ]);
 64	
 65	    // Handle "All nodes" selection directly in the click handler
 66	    const handleAllNodesClick = React.useCallback(() => {
 67	      setIsUseAllNodes(true);
 68	      if (allNodesLoaded && allNodes.length > 0) {
 69	        onNodeSelect(allNodes);
 70	      }
 71	    }, [allNodesLoaded, allNodes, onNodeSelect]);
 72	
 73	    // Handle "Select Nodes" selection - clear previous selection
 74	    const handleSelectNodesClick = React.useCallback(() => {
 75	      setIsUseAllNodes(false);
 76	      setSelectedNodes([]);
 77	    }, [setSelectedNodes]);
 78	
 79	    const defaultAllNodesDescription = t(
 80	      'All non control plane nodes are selected to handle requests to IBM Scale'
 81	    );
 82	    const defaultSelectNodesDescription = t(
 83	      'Select a minimum of 3 nodes to handle requests to IBM scale'
 84	    );
 85	
 86	    return (
 87	      <>
 88	        <Flex direction={{ default: 'row' }}>
 89	          <FlexItem>
 90	            <Card
 91	              className="odf-nodes-section__card"
 92	              isSelected={isUseAllNodes}
 93	              isRounded
 94	              isSelectable
 95	              id="all-nodes"
 96	              isDisabled={isDisabled}
 97	            >
 98	              <CardHeader
 99	                selectableActions={{
100	                  onChange: handleAllNodesClick,
101	                  selectableActionId: 'use-all-nodes',
102	                  variant: 'single',
103	                  name: 'node-selector',
104	                  selectableActionAriaLabelledby: 'all-nodes',
105	                }}
106	              >
107	                <CardTitle>{t('All Nodes (Default)')}</CardTitle>
108	              </CardHeader>
109	              <CardBody>
110	                {allNodesDescription || defaultAllNodesDescription}
111	              </CardBody>
112	            </Card>
113	          </FlexItem>
114	          <FlexItem>
115	            <Card
116	              className="odf-nodes-section__card"
117	              isSelected={!isUseAllNodes}
118	              isRounded
119	              isSelectable
120	              id="selected-nodes"
121	              isDisabled={isDisabled}
122	            >
123	              <CardHeader
124	                selectableActions={{
125	                  onChange: handleSelectNodesClick,
126	                  selectableActionId: 'use-selected-nodes',
127	                  variant: 'single',
128	                  name: 'node-selector',
129	                  selectableActionAriaLabelledby: 'selected-nodes',
130	                }}
131	              >
132	                <CardTitle>{t('Select Nodes')}</CardTitle>
133	              </CardHeader>
134	              <CardBody>
135	                {selectNodesDescription || defaultSelectNodesDescription}
136	              </CardBody>
137	            </Card>
138	          </FlexItem>
139	        </Flex>
140	        {!isUseAllNodes && (
141	          <SelectNodesTable
142	            nodes={selectedNodes}
143	            onRowSelected={onNodeSelect}
144	            systemNamespace={''}
145	          />
146	        )}
147	        {isDisabled && (
148	          <Alert
149	            variant="info"
150	            title={t('Nodes are disabled')}
151	            isInline
152	            className="pf-v6-u-mt-md"
153	          >
154	            {t('Nodes are disabled because the local cluster is configured')}
155	          </Alert>
156	        )}
157	      </>
158	    );
159	  }
160	);

